import requests
import json
from requests.auth import HTTPBasicAuth

RABBITMQ_API_URL = "http://localhost:15672/api"
USERNAME = "guest"
PASSWORD = "guest"

def create_vhost(vhost):
    url = f"{RABBITMQ_API_URL}/vhosts/{vhost}"
    response = requests.put(url, auth=HTTPBasicAuth(USERNAME, PASSWORD))
    return response.status_code

def set_user_permissions(vhost, user, permissions):
    url = f"{RABBITMQ_API_URL}/permissions/{vhost}/{user}"
    response = requests.put(url, auth=HTTPBasicAuth(USERNAME, PASSWORD), data=json.dumps(permissions), headers={'Content-Type': 'application/json'})
    return response.status_code

def main():
    vhosts = ['app1_vhost', 'app2_vhost']
    users_permissions = {
        'app_user1': {'configure': '.*', 'read': '.*', 'write': '.*'},
        'app_user2': {'configure': '.*', 'read': '.*', 'write': '.*'}
    }

    for vhost in vhosts:
        if create_vhost(vhost) == 201:
            print(f"Created vhost: {vhost}")
        else:
            print(f"Failed to create vhost: {vhost}")

        for user, permissions in users_permissions.items():
            if set_user_permissions(vhost, user, permissions) == 204:
                print(f"Set permissions for user: {user} on vhost: {vhost}")
            else:
                print(f"Failed to set permissions for user: {user} on vhost: {vhost}")

if __name__ == "__main__":
    main()